 1	import React, { useMemo, VFC } from 'react';
 2	
 3	import { V1Template } from '@kubevirt-ui/kubevirt-api/console';
 4	import { V1beta1DataSource } from '@kubevirt-ui/kubevirt-api/containerized-data-importer/models';
 5	import { VirtualizedTable } from '@openshift-console/dynamic-plugin-sdk';
 6	import { Gallery, StackItem } from '@patternfly/react-core';
 7	
 8	import useTemplatesCatalogColumns from '../hooks/useTemplatesCatalogColumns';
 9	import { TemplateFilters } from '../utils/types';
10	
11	import { TemplatesCatalogRow } from './TemplatesCatalogRow';
12	import { TemplateTile } from './TemplatesCatalogTile';
13	
14	type TemplatesCatalogItemsProps = {
15	  availableDatasources: Record<string, V1beta1DataSource>;
16	  availableTemplatesUID: Set<string>;
17	  bootSourcesLoaded: boolean;
18	  filters: TemplateFilters;
19	  loaded: boolean;
20	  onTemplateClick: (template: V1Template) => void;
21	  templates: V1Template[];
22	};
23	
24	export const TemplatesCatalogItems: VFC<TemplatesCatalogItemsProps> = ({
25	  availableDatasources,
26	  availableTemplatesUID,
27	  bootSourcesLoaded,
28	  filters,
29	  loaded,
30	  onTemplateClick,
31	  templates,
32	}) => {
33	  const columns = useTemplatesCatalogColumns();
34	
35	  const sortedTemplates = useMemo(
36	    () =>
37	      templates.sort((a: V1Template, b: V1Template) =>
38	        a?.metadata?.name?.localeCompare(b?.metadata?.name),
39	      ),
40	    [templates],
41	  );
42	
43	  return filters?.isList ? (
44	    <div className="vm-catalog-table-container">
45	      <VirtualizedTable
46	        columns={columns}
47	        data={templates}
48	        loaded={loaded && bootSourcesLoaded}
49	        loadError={null}
50	        Row={TemplatesCatalogRow}
51	        rowData={{ availableDatasources, availableTemplatesUID, onTemplateClick }}
52	        unfilteredData={templates}
53	      />
54	    </div>
55	  ) : (
56	    <StackItem className="co-catalog-page__grid vm-catalog-grid-container">
57	      <Gallery className="vm-catalog-grid" hasGutter id="vm-catalog-grid">
58	        {sortedTemplates.map((template) => (
59	          <TemplateTile
60	            availableDatasources={availableDatasources}
61	            availableTemplatesUID={availableTemplatesUID}
62	            bootSourcesLoaded={bootSourcesLoaded}
63	            key={template?.metadata?.uid}
64	            onClick={onTemplateClick}
65	            template={template}
66	          />
67	        ))}
68	      </Gallery>
69	    </StackItem>
70	  );
71	};

